import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encoding user input before outputting it to the web page
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        // Output sanitized user input to prevent XSS attacks
        System.out.println("<html>");
        System.out.println("<head><title>XSS Secure Example</title></head>");
        System.out.println("<body>");
        System.out.println("<h1>Hello, " + encodedUserInput + "</h1>");
        System.out.println("</body>");
        System.out.println("</html>");

        // The script tag will be displayed as plain text and not executed as HTML
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
